9	//------------------------------------------------------------------
10	// Test module.
11	//------------------------------------------------------------------
12	module tb_aes_key_mem();
13	
14	  //----------------------------------------------------------------
15	  // Internal constant and parameter definitions.
16	  //----------------------------------------------------------------
17	  parameter DEBUG = 1;
18	  parameter SHOW_SBOX = 0;
19	
20	  parameter CLK_HALF_PERIOD = 1;
21	  parameter CLK_PERIOD = 2 * CLK_HALF_PERIOD;
22	
23	  parameter AES_128_BIT_KEY = 0;
24	  parameter AES_256_BIT_KEY = 1;
25	
26	  parameter AES_128_NUM_ROUNDS = 10;
27	  parameter AES_256_NUM_ROUNDS = 14;
28	
29	  parameter AES_DECIPHER = 1'b0;
30	  parameter AES_ENCIPHER = 1'b1;
31	
32	
33	  //----------------------------------------------------------------
34	  // Register and Wire declarations.
35	  //----------------------------------------------------------------
36	  reg [31 : 0] cycle_ctr;
37	  reg [31 : 0] error_ctr;
38	  reg [31 : 0] tc_ctr;
39	
40	  reg            tb_clk;
41	  reg            tb_reset_n;
42	  reg [255 : 0]  tb_key;
43	  reg            tb_keylen;
44	  reg            tb_init;
45	  reg [3 : 0]    tb_round;
46	  wire [127 : 0] tb_round_key;
47	  wire           tb_ready;
48	
49	  wire [31 : 0]  tb_sboxw;
50	  wire [31 : 0]  tb_new_sboxw;
51	
52	
53	  //----------------------------------------------------------------
54	  // Device Under Test.
55	  //----------------------------------------------------------------
56	  aes_key_mem dut(
57	                  .clk(tb_clk),
58	                  .reset_n(tb_reset_n),
59	
60	                  .key(tb_key),
61	                  .keylen(tb_keylen),
62	                  .init(tb_init),
63	
64	                  .round(tb_round),
65	                  .round_key(tb_round_key),
66	                  .ready(tb_ready),
67	
68	                  .sboxw(tb_sboxw),
69	                  .new_sboxw(tb_new_sboxw)
70	                 );
71	
72	  // The DUT requirees Sboxes.
73	  aes_sbox sbox(.sboxw(tb_sboxw), .new_sboxw(tb_new_sboxw));
74	
75	
76	  //----------------------------------------------------------------
77	  // clk_gen
78	  //
79	  // Always running clock generator process.
80	  //----------------------------------------------------------------
81	  always
82	    begin : clk_gen
83	      #CLK_HALF_PERIOD;
84	      tb_clk = !tb_clk;
85	    end // clk_gen
86	
87	
88	  //----------------------------------------------------------------
89	  // sys_monitor()
90	  //
91	  // An always running process that creates a cycle counter and
92	  // conditionally displays information about the DUT.
93	  //----------------------------------------------------------------
94	  always
95	    begin : sys_monitor
96	      cycle_ctr = cycle_ctr + 1;
97	      #(CLK_PERIOD);
98	      if (DEBUG)
99	        begin
100	          dump_dut_state();
101	        end
102	    end
103	
104	
105	  //----------------------------------------------------------------
106	  // dump_dut_state()
107	  //
108	  // Dump the state of the dump when needed.
109	  //----------------------------------------------------------------
110	  task dump_dut_state;
111	    begin
112	      $display("State of DUT");
113	      $display("------------");
114	      $display("Inputs and outputs:");
115	      $display("key       = 0x%032x", dut.key);
116	      $display("keylen    = 0x%01x, init = 0x%01x, ready = 0x%01x",
117	               dut.keylen, dut.init, dut.ready);
118	      $display("round     = 0x%02x", dut.round);
119	      $display("round_key = 0x%016x", dut.round_key);
120	      $display("");
121	
122	      $display("Internal states:");
123	      $display("key_mem_ctrl = 0x%01x, round_key_update = 0x%01x, round_ctr_reg = 0x%01x, rcon_reg = 0x%01x",
124	               dut.key_mem_ctrl_reg, dut.round_key_update, dut.round_ctr_reg, dut.rcon_reg);
125	
126	      $display("prev_key0_reg = 0x%016x, prev_key0_new = 0x%016x, prev_key0_we = 0x%01x",
127	               dut.prev_key0_reg, dut.prev_key0_new, dut.prev_key0_we);
128	      $display("prev_key1_reg = 0x%016x, prev_key1_new = 0x%016x, prev_key1_we = 0x%01x",
129	               dut.prev_key1_reg, dut.prev_key1_new, dut.prev_key1_we);
130	
131	      $display("w0 = 0x%04x, w1 = 0x%04x, w2 = 0x%04x, w3 = 0x%04x",
132	               dut.round_key_gen.w0, dut.round_key_gen.w1,
133	               dut.round_key_gen.w2, dut.round_key_gen.w3);
134	      $display("w4 = 0x%04x, w5 = 0x%04x, w6 = 0x%04x, w7 = 0x%04x",
135	               dut.round_key_gen.w4, dut.round_key_gen.w5,
136	               dut.round_key_gen.w6, dut.round_key_gen.w7);
137	      $display("sboxw = 0x%04x, new_sboxw = 0x%04x, rconw = 0x%04x",
138	               dut.sboxw, dut.new_sboxw, dut.round_key_gen.rconw);
139	      $display("tw = 0x%04x, trw = 0x%04x", dut.round_key_gen.tw, dut.round_key_gen.trw);
140	      $display("key_mem_new = 0x%016x, key_mem_we = 0x%01x",
141	               dut.key_mem_new, dut.key_mem_we);
142	      $display("");
143	
144	      if (SHOW_SBOX)
145	        begin
146	          $display("Sbox functionality:");
147	          $display("sboxw = 0x%08x", sbox.sboxw);
148	          $display("tmp_new_sbox0 = 0x%02x, tmp_new_sbox1 = 0x%02x, tmp_new_sbox2 = 0x%02x, tmp_new_sbox3",
149	                   sbox.tmp_new_sbox0, sbox.tmp_new_sbox1, sbox.tmp_new_sbox2, sbox.tmp_new_sbox3);
150	          $display("new_sboxw = 0x%08x", sbox.new_sboxw);
151	          $display("");
152	        end
153	    end
154	  endtask // dump_dut_state
