157	  //----------------------------------------------------------------
158	  // reset_dut()
159	  //
160	  // Toggle reset to put the DUT into a well known state.
161	  //----------------------------------------------------------------
162	  task reset_dut;
163	    begin
164	      $display("*** Toggle reset.");
165	      tb_reset_n = 0;
166	      #(2 * CLK_PERIOD);
167	      tb_reset_n = 1;
168	    end
169	  endtask // reset_dut
170	
171	
172	  //----------------------------------------------------------------
173	  // init_sim()
174	  //
175	  // Initialize all counters and testbed functionality as well
176	  // as setting the DUT inputs to defined values.
177	  //----------------------------------------------------------------
178	  task init_sim;
179	    begin
180	      cycle_ctr = 0;
181	      error_ctr = 0;
182	      tc_ctr    = 0;
183	
184	      tb_clk     = 0;
185	      tb_reset_n = 1;
186	      tb_key     = {8{32'h00000000}};
187	      tb_keylen  = 0;
188	      tb_init    = 0;
189	      tb_round   = 4'h0;
190	    end
191	  endtask // init_sim
192	
193	
194	  //----------------------------------------------------------------
195	  // wait_ready()
196	  //
197	  // Wait for the ready flag in the dut to be set.
198	  //
199	  // Note: It is the callers responsibility to call the function
200	  // when the dut is actively processing and will in fact at some
201	  // point set the flag.
202	  //----------------------------------------------------------------
203	  task wait_ready;
204	    begin
205	      while (!tb_ready)
206	        begin
207	          #(CLK_PERIOD);
208	        end
209	    end
210	  endtask // wait_ready
211	
212	
213	  //----------------------------------------------------------------
214	  // check_key()
215	  //
216	  // Check a given key in the dut key memory against a given
217	  // expected key.
218	  //----------------------------------------------------------------
219	  task check_key(input [3 : 0] key_nr, input [127 : 0] expected);
220	    begin
221	      tb_round = key_nr;
222	      #(CLK_PERIOD);
223	      if (tb_round_key == expected)
224	        begin
225	          $display("** key 0x%01x matched expected round key.", key_nr);
226	          $display("** Got:      0x%016x **", tb_round_key);
227	        end
228	      else
229	        begin
230	          $display("** Error: key 0x%01x did not match expected round key. **", key_nr);
231	          $display("** Expected: 0x%016x **", expected);
232	          $display("** Got:      0x%016x **", tb_round_key);
233	          error_ctr = error_ctr + 1;
234	        end
235	      $display("");
236	    end
237	  endtask // check_key
238	
239	
240	  //----------------------------------------------------------------
241	  // test_key_128()
242	  //
243	  // Test 128 bit keys. Due to array problems, the result check
244	  // is fairly ugly.
245	  //----------------------------------------------------------------
246	  task test_key_128(input [255 : 0] key,
247	                    input [127 : 0] expected00,
248	                    input [127 : 0] expected01,
249	                    input [127 : 0] expected02,
250	                    input [127 : 0] expected03,
251	                    input [127 : 0] expected04,
252	                    input [127 : 0] expected05,
253	                    input [127 : 0] expected06,
254	                    input [127 : 0] expected07,
255	                    input [127 : 0] expected08,
256	                    input [127 : 0] expected09,
257	                    input [127 : 0] expected10
258	                   );
259	    begin
260	      $display("** Testing with 128-bit key 0x%16x", key[255 : 128]);
261	      $display("");
262	
263	      tb_key = key;
264	      tb_keylen = AES_128_BIT_KEY;
265	      tb_init = 1;
266	      #(2 * CLK_PERIOD);
267	      tb_init = 0;
268	      wait_ready();
269	
270	      check_key(4'h0, expected00);
271	      check_key(4'h1, expected01);
272	      check_key(4'h2, expected02);
273	      check_key(4'h3, expected03);
274	      check_key(4'h4, expected04);
275	      check_key(4'h5, expected05);
276	      check_key(4'h6, expected06);
277	      check_key(4'h7, expected07);
278	      check_key(4'h8, expected08);
279	      check_key(4'h9, expected09);
280	      check_key(4'ha, expected10);
281	
282	      tc_ctr = tc_ctr + 1;
283	    end
284	  endtask // test_key_128
