325	      check_key(4'h3, expected03);
326	      check_key(4'h4, expected04);
327	      check_key(4'h5, expected05);
328	      check_key(4'h6, expected06);
329	      check_key(4'h7, expected07);
330	      check_key(4'h8, expected08);
