352	          $display("*** All %02d test cases completed successfully", tc_ctr);
353	        end
354	      else
355	        begin
356	          $display("*** %02d tests completed - %02d test cases did not complete successfully.",
357	                   tc_ctr, error_ctr);
358	        end
359	    end
360	  endtask // display_test_result
