1	//======================================================================
2	//
3	// tb_aes_core.v
4	// -------------
5	// Testbench for the AES block cipher core.
6	//
7	//======================================================================
8	
9	//------------------------------------------------------------------
10	// Test module.
11	//------------------------------------------------------------------
12	module tb_aes_core();
13	
14	  //----------------------------------------------------------------
15	  // Internal constant and parameter definitions.
16	  //----------------------------------------------------------------
17	  parameter DEBUG     = 0;
18	  parameter DUMP_WAIT = 0;
19	
20	  parameter CLK_HALF_PERIOD = 1;
21	  parameter CLK_PERIOD = 2 * CLK_HALF_PERIOD;
22	
23	  parameter AES_128_BIT_KEY = 0;
24	  parameter AES_256_BIT_KEY = 1;
25	
26	  parameter AES_DECIPHER = 1'b0;
27	  parameter AES_ENCIPHER = 1'b1;
28	
29	
30	  //----------------------------------------------------------------
31	  // Register and Wire declarations.
32	  //----------------------------------------------------------------
33	  reg [31 : 0] cycle_ctr;
34	  reg [31 : 0] error_ctr;
35	  reg [31 : 0] tc_ctr;
36	
37	  reg            tb_clk;
38	  reg            tb_reset_n;
39	  reg            tb_encdec;
40	  reg            tb_init;
41	  reg            tb_next;
42	  wire           tb_ready;
43	  reg [255 : 0]  tb_key;
44	  reg            tb_keylen;
45	  reg [127 : 0]  tb_block;
46	  wire [127 : 0] tb_result;
47	  wire           tb_result_valid;
48	
49	
50	  //----------------------------------------------------------------
51	  // Device Under Test.
52	  //----------------------------------------------------------------
53	  aes_core dut(
54	               .clk(tb_clk),
55	               .reset_n(tb_reset_n),
56	
57	               .encdec(tb_encdec),
58	               .init(tb_init),
59	               .next(tb_next),
60	               .ready(tb_ready),
61	
62	               .key(tb_key),
63	               .keylen(tb_keylen),
64	
65	               .block(tb_block),
66	               .result(tb_result)
67	              );
68	
69	
70	  //----------------------------------------------------------------
71	  // clk_gen
72	  //
73	  // Always running clock generator process.
74	  //----------------------------------------------------------------
75	  always
76	    begin : clk_gen
77	      #CLK_HALF_PERIOD;
78	      tb_clk = !tb_clk;
79	    end // clk_gen
80	
81	
82	  //----------------------------------------------------------------
83	  // sys_monitor()
84	  //
85	  // An always running process that creates a cycle counter and
86	  // conditionally displays information about the DUT.
87	  //----------------------------------------------------------------
88	  always
89	    begin : sys_monitor
90	      cycle_ctr = cycle_ctr + 1;
91	      #(CLK_PERIOD);
92	      if (DEBUG)
93	        begin
94	          dump_dut_state();
95	        end
96	    end
97	
98	
99	  //----------------------------------------------------------------
100	  // dump_dut_state()
101	  //
102	  // Dump the state of the dump when needed.
103	  //----------------------------------------------------------------
104	  task dump_dut_state;
105	    begin
106	      $display("State of DUT");
107	      $display("------------");
108	      $display("Inputs and outputs:");
109	      $display("encdec = 0x%01x, init = 0x%01x, next = 0x%01x",
110	               dut.encdec, dut.init, dut.next);
111	      $display("keylen = 0x%01x, key  = 0x%032x ", dut.keylen, dut.key);
112	      $display("block  = 0x%032x", dut.block);
113	      $display("");
114	      $display("ready        = 0x%01x", dut.ready);
115	      $display("result_valid = 0x%01x, result = 0x%032x",
116	               dut.result_valid, dut.result);
117	      $display("");
118	      $display("Encipher state::");
119	      $display("enc_ctrl = 0x%01x, round_ctr = 0x%01x",
120	               dut.enc_block.enc_ctrl_reg, dut.enc_block.round_ctr_reg);
121	      $display("");
122	    end
123	  endtask // dump_dut_state
124	
125	
126	  //----------------------------------------------------------------
127	  // dump_keys()
128	  //
129	  // Dump the keys in the key memory of the dut.
130	  //----------------------------------------------------------------
131	  task dump_keys;
132	    begin
133	      $display("State of key memory in DUT:");
134	      $display("key[00] = 0x%016x", dut.keymem.key_mem[00]);
135	      $display("key[01] = 0x%016x", dut.keymem.key_mem[01]);
136	      $display("key[02] = 0x%016x", dut.keymem.key_mem[02]);
137	      $display("key[03] = 0x%016x", dut.keymem.key_mem[03]);
138	      $display("key[04] = 0x%016x", dut.keymem.key_mem[04]);
139	      $display("key[05] = 0x%016x", dut.keymem.key_mem[05]);
140	      $display("key[06] = 0x%016x", dut.keymem.key_mem[06]);
141	      $display("key[07] = 0x%016x", dut.keymem.key_mem[07]);
142	      $display("key[08] = 0x%016x", dut.keymem.key_mem[08]);
143	      $display("key[09] = 0x%016x", dut.keymem.key_mem[09]);
144	      $display("key[10] = 0x%016x", dut.keymem.key_mem[10]);
145	      $display("key[11] = 0x%016x", dut.keymem.key_mem[11]);
146	      $display("key[12] = 0x%016x", dut.keymem.key_mem[12]);
147	      $display("key[13] = 0x%016x", dut.keymem.key_mem[13]);
148	      $display("key[14] = 0x%016x", dut.keymem.key_mem[14]);
149	      $display("");
150	    end
151	  endtask // dump_keys
152	
153	
154	  //----------------------------------------------------------------
155	  // reset_dut()
156	  //
157	  // Toggle reset to put the DUT into a well known state.
158	  //----------------------------------------------------------------
159	  task reset_dut;
160	    begin
161	      $display("*** Toggle reset.");
162	      tb_reset_n = 0;
163	      #(2 * CLK_PERIOD);
164	      tb_reset_n = 1;
165	    end
166	  endtask // reset_dut
167	
168	
169	  //----------------------------------------------------------------
170	  // init_sim()
171	  //
172	  // Initialize all counters and testbed functionality as well
173	  // as setting the DUT inputs to defined values.
174	  //----------------------------------------------------------------
175	  task init_sim;
176	    begin
177	      cycle_ctr = 0;
178	      error_ctr = 0;
179	      tc_ctr    = 0;
180	
181	      tb_clk     = 0;
182	      tb_reset_n = 1;
183	      tb_encdec  = 0;
184	      tb_init    = 0;
185	      tb_next    = 0;
186	      tb_key     = {8{32'h00000000}};
187	      tb_keylen  = 0;
188	
189	      tb_block  = {4{32'h00000000}};
190	    end
191	  endtask // init_sim
192	
193	
194	  //----------------------------------------------------------------
195	  // display_test_result()
196	  //
197	  // Display the accumulated test results.
198	  //----------------------------------------------------------------
199	  task display_test_result;
200	    begin
201	      if (error_ctr == 0)
202	        begin
203	          $display("*** All %02d test cases completed successfully", tc_ctr);
204	        end
205	      else
206	        begin
207	          $display("*** %02d tests completed - %02d test cases did not complete successfully.",
208	                   tc_ctr, error_ctr);
209	        end
210	    end
211	  endtask // display_test_result
212	
213	
214	  //----------------------------------------------------------------
215	  // wait_ready()
216	  //
217	  // Wait for the ready flag in the dut to be set.
218	  //
219	  // Note: It is the callers responsibility to call the function
220	  // when the dut is actively processing and will in fact at some
221	  // point set the flag.
222	  //----------------------------------------------------------------
223	  task wait_ready;
224	    begin
225	      while (!tb_ready)
226	        begin
227	          #(CLK_PERIOD);
228	          if (DUMP_WAIT)
229	            begin
230	              dump_dut_state();
231	            end
232	        end
233	    end
234	  endtask // wait_ready
235	
236	
237	  //----------------------------------------------------------------
238	  // wait_valid()
239	  //
240	  // Wait for the result_valid flag in the dut to be set.
241	  //
242	  // Note: It is the callers responsibility to call the function
243	  // when the dut is actively processing a block and will in fact
244	  // at some point set the flag.
245	  //----------------------------------------------------------------
246	  task wait_valid;
247	    begin
248	      while (!tb_result_valid)
249	        begin
250	          #(CLK_PERIOD);
251	        end
252	    end
253	  endtask // wait_valid
254	
255	
256	  //----------------------------------------------------------------
257	  // ecb_mode_single_block_test()
258	  //
259	  // Perform ECB mode encryption or decryption single block test.
260	  //----------------------------------------------------------------
261	  task ecb_mode_single_block_test(input [7 : 0]   tc_number,
262	                                  input           encdec,
263	                                  input [255 : 0] key,
264	                                  input           key_length,
265	                                  input [127 : 0] block,
266	                                  input [127 : 0] expected);
267	   begin
268	     $display("*** TC %0d ECB mode test started.", tc_number);
269	     tc_ctr = tc_ctr + 1;
270	
271	     // Init the cipher with the given key and length.
272	     tb_key = key;
273	     tb_keylen = key_length;
274	     tb_init = 1;
275	     #(2 * CLK_PERIOD);
276	     tb_init = 0;
277	     wait_ready();
278	
279	     $display("Key expansion done");
280	     $display("");
281	
282	     dump_keys();
283	
284	
285	     // Perform encipher och decipher operation on the block.
286	     tb_encdec = encdec;
287	     tb_block = block;
288	     tb_next = 1;
289	     #(2 * CLK_PERIOD);
290	     tb_next = 0;
291	     wait_ready();
292	
293	     if (tb_result == expected)
294	       begin
295	         $display("*** TC %0d successful.", tc_number);
296	         $display("");
297	       end
298	     else
299	       begin
300	         $display("*** ERROR: TC %0d NOT successful.", tc_number);
301	         $display("Expected: 0x%032x", expected);
302	         $display("Got:      0x%032x", tb_result);
303	         $display("");
304	
305	         error_ctr = error_ctr + 1;
306	       end
307	   end
308	  endtask // ecb_mode_single_block_test
309	
310	
311	  //----------------------------------------------------------------
312	  // aes_core_test
313	  // The main test functionality.
314	  //
315	  // Test cases taken from NIST SP 800-38A:
316	  // http://csrc.nist.gov/publications/nistpubs/800-38a/sp800-38a.pdf
317	  //----------------------------------------------------------------
318	  initial
319	    begin : aes_core_test
320	      reg [255 : 0] nist_aes128_key;
321	      reg [255 : 0] nist_aes256_key;
322	
323	      reg [127 : 0] nist_plaintext0;
324	      reg [127 : 0] nist_plaintext1;
325	      reg [127 : 0] nist_plaintext2;
326	      reg [127 : 0] nist_plaintext3;
327	
328	      reg [127 : 0] nist_ecb_128_enc_expected0;
329	      reg [127 : 0] nist_ecb_128_enc_expected1;
330	      reg [127 : 0] nist_ecb_128_enc_expected2;
331	      reg [127 : 0] nist_ecb_128_enc_expected3;
332	
333	      reg [127 : 0] nist_ecb_256_enc_expected0;
334	      reg [127 : 0] nist_ecb_256_enc_expected1;
335	      reg [127 : 0] nist_ecb_256_enc_expected2;
336	      reg [127 : 0] nist_ecb_256_enc_expected3;
337	
338	      nist_aes128_key = 256'h2b7e151628aed2a6abf7158809cf4f3c00000000000000000000000000000000;
339	      nist_aes256_key = 256'h603deb1015ca71be2b73aef0857d77811f352c073b6108d72d9810a30914dff4;
340	
341	      nist_plaintext0 = 128'h6bc1bee22e409f96e93d7e117393172a;
342	      nist_plaintext1 = 128'hae2d8a571e03ac9c9eb76fac45af8e51;
343	      nist_plaintext2 = 128'h30c81c46a35ce411e5fbc1191a0a52ef;
344	      nist_plaintext3 = 128'hf69f2445df4f9b17ad2b417be66c3710;
345	
346	      nist_ecb_128_enc_expected0 = 128'h3ad77bb40d7a3660a89ecaf32466ef97;
347	      nist_ecb_128_enc_expected1 = 128'hf5d3d58503b9699de785895a96fdbaaf;
348	      nist_ecb_128_enc_expected2 = 128'h43b1cd7f598ece23881b00e3ed030688;
349	      nist_ecb_128_enc_expected3 = 128'h7b0c785e27e8ad3f8223207104725dd4;
350	
351	      nist_ecb_256_enc_expected0 = 128'hf3eed1bdb5d2a03c064b5a7e3db181f8;
352	      nist_ecb_256_enc_expected1 = 128'h591ccb10d410ed26dc5ba74a31362870;
353	      nist_ecb_256_enc_expected2 = 128'hb6ed21b99ca6f4f9f153e7b1beafed1d;
354	      nist_ecb_256_enc_expected3 = 128'h23304b7a39f9f3ff067d8d8f9e24ecc7;
355	
356	
357	      $display("   -= Testbench for aes core started =-");
358	      $display("     ================================");
359	      $display("");
360	
361	      init_sim();
362	      dump_dut_state();
363	      reset_dut();
364	      dump_dut_state();
365	
366	
367	      $display("ECB 128 bit key tests");
368	      $display("---------------------");
369	      ecb_mode_single_block_test(8'h01, AES_ENCIPHER, nist_aes128_key, AES_128_BIT_KEY,
370	                                 nist_plaintext0, nist_ecb_128_enc_expected0);
371	
372	     ecb_mode_single_block_test(8'h02, AES_ENCIPHER, nist_aes128_key, AES_128_BIT_KEY,
373	                                nist_plaintext1, nist_ecb_128_enc_expected1);
374	
375	     ecb_mode_single_block_test(8'h03, AES_ENCIPHER, nist_aes128_key, AES_128_BIT_KEY,
376	                                nist_plaintext2, nist_ecb_128_enc_expected2);
377	
378	     ecb_mode_single_block_test(8'h04, AES_ENCIPHER, nist_aes128_key, AES_128_BIT_KEY,
379	                                nist_plaintext3, nist_ecb_128_enc_expected3);
380	
381	
382	      ecb_mode_single_block_test(8'h05, AES_DECIPHER, nist_aes128_key, AES_128_BIT_KEY,
383	                                 nist_ecb_128_enc_expected0, nist_plaintext0);
384	
385	      ecb_mode_single_block_test(8'h06, AES_DECIPHER, nist_aes128_key, AES_128_BIT_KEY,
386	                                 nist_ecb_128_enc_expected1, nist_plaintext1);
387	
388	      ecb_mode_single_block_test(8'h07, AES_DECIPHER, nist_aes128_key, AES_128_BIT_KEY,
389	                                 nist_ecb_128_enc_expected2, nist_plaintext2);
390	
391	      ecb_mode_single_block_test(8'h08, AES_DECIPHER, nist_aes128_key, AES_128_BIT_KEY,
392	                                 nist_ecb_128_enc_expected3, nist_plaintext3);
393	
394	
395	      $display("");
396	      $display("ECB 256 bit key tests");
397	      $display("---------------------");
398	      ecb_mode_single_block_test(8'h10, AES_ENCIPHER, nist_aes256_key, AES_256_BIT_KEY,
399	                                 nist_plaintext0, nist_ecb_256_enc_expected0);
400	
401	      ecb_mode_single_block_test(8'h11, AES_ENCIPHER, nist_aes256_key, AES_256_BIT_KEY,
402	                                 nist_plaintext1, nist_ecb_256_enc_expected1);
403	
404	      ecb_mode_single_block_test(8'h12, AES_ENCIPHER, nist_aes256_key, AES_256_BIT_KEY,
405	                                 nist_plaintext2, nist_ecb_256_enc_expected2);
406	
407	      ecb_mode_single_block_test(8'h13, AES_ENCIPHER, nist_aes256_key, AES_256_BIT_KEY,
408	                                 nist_plaintext3, nist_ecb_256_enc_expected3);
409	
410	
411	      ecb_mode_single_block_test(8'h14, AES_DECIPHER, nist_aes256_key, AES_256_BIT_KEY,
412	                                 nist_ecb_256_enc_expected0, nist_plaintext0);
413	
414	      ecb_mode_single_block_test(8'h15, AES_DECIPHER, nist_aes256_key, AES_256_BIT_KEY,
415	                                 nist_ecb_256_enc_expected1, nist_plaintext1);
416	
417	      ecb_mode_single_block_test(8'h16, AES_DECIPHER, nist_aes256_key, AES_256_BIT_KEY,
418	                                 nist_ecb_256_enc_expected2, nist_plaintext2);
419	
420	      ecb_mode_single_block_test(8'h17, AES_DECIPHER, nist_aes256_key, AES_256_BIT_KEY,
421	                                 nist_ecb_256_enc_expected3, nist_plaintext3);
422	
423	
424	      display_test_result();
425	      $display("");
426	      $display("*** AES core simulation done. ***");
427	      $finish;
428	    end // aes_core_test
429	endmodule // tb_aes_core
